import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

export default function ChatPage() {
  const { taskId } = useParams();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [messages, setMessages] = useState([]);
  const [task, setTask] = useState(null);
  const [text, setText] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const bottomRef = useRef(null);

  const fetchMessages = async () => {
    try {
      const res = await api.get(`/messages/${taskId}`);
      setMessages(res.data);
    } catch {}
  };

  useEffect(() => {
    if (!user) return navigate('/signin');
    api.get(`/tasks/${taskId}`).then(res => setTask(res.data)).catch(() => {});
    fetchMessages().finally(() => setLoading(false));

    // Poll every 3 seconds
    const interval = setInterval(fetchMessages, 3000);
    return () => clearInterval(interval);
  }, [taskId]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if (!text.trim()) return;
    setSending(true);
    try {
      const res = await api.post(`/messages/${taskId}`, { content: text.trim() });
      setMessages(prev => [...prev, res.data]);
      setText('');
    } catch (err) {
      alert(err.response?.data?.error || 'Ошибка');
    } finally {
      setSending(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const otherName = task
    ? (user?.id === task.customer_id ? task.helper_name : task.customer_name)
    : '...';

  return (
    <div className="app-container" style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      {/* Header */}
      <div style={{
        padding: '12px 16px', background: 'white',
        borderBottom: '1px solid var(--border)',
        display: 'flex', alignItems: 'center', gap: 12
      }}>
        <button className="back-btn" onClick={() => navigate(-1)}>←</button>
        <div style={{
          width: 38, height: 38, borderRadius: '50%', background: 'var(--green-pale)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontWeight: 700, color: 'var(--green)', fontSize: 16
        }}>
          {otherName?.[0]?.toUpperCase() || '?'}
        </div>
        <div>
          <div style={{ fontWeight: 700, fontSize: 15 }}>{otherName}</div>
          {task && <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{task.title}</div>}
        </div>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '16px', display: 'flex', flexDirection: 'column', gap: 10 }}>
        {loading && <div className="loading"><div className="spinner" /></div>}
        {!loading && messages.length === 0 && (
          <div style={{ textAlign: 'center', color: 'var(--text-muted)', marginTop: 40, fontSize: 14 }}>
            Начните общение 👋
          </div>
        )}
        {messages.map(msg => {
          const isMine = Number(msg.sender_id) === Number(user?.id);
          return (
            <div
              key={msg.id}
              style={{
                display: 'flex',
                justifyContent: isMine ? 'flex-end' : 'flex-start'
              }}
            >
              <div style={{
                maxWidth: '75%',
                background: isMine ? 'var(--green)' : 'white',
                color: isMine ? 'white' : 'var(--text)',
                padding: '10px 14px',
                borderRadius: isMine ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
                boxShadow: 'var(--shadow)',
                fontSize: 15,
                lineHeight: 1.4
              }}>
                {msg.content}
                <div style={{
                  fontSize: 10, marginTop: 4,
                  color: isMine ? 'rgba(255,255,255,0.6)' : 'var(--text-muted)',
                  textAlign: 'right'
                }}>
                  {new Date(msg.created_at).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          );
        })}
        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div style={{
        padding: '12px 16px', background: 'white',
        borderTop: '1px solid var(--border)',
        display: 'flex', gap: 10, alignItems: 'flex-end'
      }}>
        <textarea
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Написать сообщение..."
          rows={1}
          style={{
            flex: 1, background: '#f1f5f0', border: '1.5px solid transparent',
            borderRadius: 20, padding: '10px 16px', fontSize: 15,
            resize: 'none', outline: 'none', fontFamily: 'inherit',
            maxHeight: 100, overflowY: 'auto'
          }}
        />
        <button
          onClick={handleSend}
          disabled={sending || !text.trim()}
          style={{
            width: 44, height: 44, borderRadius: '50%',
            background: text.trim() ? 'var(--green)' : '#e5e7eb',
            border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 18, transition: 'background 0.2s', flexShrink: 0
          }}
        >
          {sending ? '...' : '➤'}
        </button>
      </div>
    </div>
  );
}
